import { Injectable } from '@angular/core';
import { Observable } from 'rxjs';
import { map } from 'rxjs/operators';
import { BaseService } from './base.service';
import { JobTitle } from '../models';
import { AuthService } from './timbrature-auth.adapter';

@Injectable({ providedIn: 'root' })
export class JobTitlesService extends BaseService<JobTitle> {
  protected override tableName = 'job_titles';

  constructor(private authService: AuthService) {
    super();
  }

  /**
   * Ottiene tutte le mansioni di un'azienda.
   * @param companyId - ID dell'azienda
   * @param includeInactive - Se true, include anche le mansioni disattivate
   */
  getByCompany(companyId: string, includeInactive = false): Observable<JobTitle[]> {
    return this.getAll(companyId).pipe(
      map(titles => includeInactive ? titles : titles.filter(t => t.is_active !== false))
    );
  }

  /**
   * Crea una nuova mansione.
   * @param companyId - ID azienda
   * @param name - Nome mansione
   * @param description - Descrizione opzionale
   */
  createJobTitle(companyId: string, name: string, description?: string | null): Observable<JobTitle> {
    const user = this.authService.currentUserSubject.value;
    if (!user) throw new Error('Utente non autenticato');

    const newTitle: Partial<JobTitle> = {
      company_id: companyId,
      name,
      description: description ?? null,
      created_by: user.id,
      is_active: true
    };
    return this.create(newTitle);
  }

  /**
   * Aggiorna una mansione esistente.
   * @param id - ID mansione
   * @param updates - Campi da aggiornare
   */
  updateJobTitle(id: string, updates: Partial<JobTitle>): Observable<JobTitle> {
    return this.update(id, updates);
  }

  /**
   * Attiva/disattiva una mansione.
   * @param id - ID mansione
   * @param isActive - true = attiva, false = disattiva
   */
  setActiveStatus(id: string, isActive: boolean): Observable<JobTitle> {
    return this.update(id, { is_active: isActive });
  }

  /**
   * Eliminazione logica (disattiva la mansione).
   * @param id - ID mansione
   */
  deleteJobTitle(id: string): Observable<JobTitle> {
    return this.update(id, { is_active: false });
  }
}
